"use strict";(globalThis.webpackChunkrenfe_tracker_docs=globalThis.webpackChunkrenfe_tracker_docs||[]).push([[661],{5359(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docsSidebar":[{"type":"link","label":"Introduction","href":"/renfe-tracker/","docId":"intro","unlisted":false},{"type":"link","label":"Installation","href":"/renfe-tracker/installation","docId":"installation","unlisted":false},{"type":"link","label":"Configuration","href":"/renfe-tracker/configuration","docId":"configuration","unlisted":false},{"type":"category","label":"Features","collapsed":false,"items":[{"type":"link","label":"Possible Trains","href":"/renfe-tracker/features/possible-trains","docId":"features/possible-trains","unlisted":false},{"type":"link","label":"Price Range","href":"/renfe-tracker/features/price-range","docId":"features/price-range","unlisted":false},{"type":"link","label":"Trip Tracking","href":"/renfe-tracker/features/trip-tracking","docId":"features/trip-tracking","unlisted":false},{"type":"link","label":"Notifications","href":"/renfe-tracker/features/notifications","docId":"features/notifications","unlisted":false}],"collapsible":true}]},"docs":{"configuration":{"id":"configuration","title":"Configuration","description":"All configuration is done through environment variables. When using Docker Compose, set them in your docker-compose.yml or a .env file in the same directory.","sidebar":"docsSidebar"},"features/notifications":{"id":"features/notifications","title":"Notifications","description":"Whenever a tracked trip changes price, Renfe Tracker can notify you immediately. Four notification systems are supported, and you can configure as many as you like \u2014 all active notifications fire on every price change.","sidebar":"docsSidebar"},"features/possible-trains":{"id":"features/possible-trains","title":"Possible Trains","description":"When you search for trains on a specific date, Renfe Tracker doesn\'t just show you the trains that Renfe has currently published for that day \u2014 it also shows you trains that haven\'t been published yet but are very likely to run.","sidebar":"docsSidebar"},"features/price-range":{"id":"features/price-range","title":"Price Range","description":"For every train shown in search results and on your tracked trips list, Renfe Tracker displays not just the current price, but also a historical price range \u2014 the minimum and maximum prices ever observed for that train on the same route and weekday.","sidebar":"docsSidebar"},"features/trip-tracking":{"id":"features/trip-tracking","title":"Trip Tracking","description":"Trip tracking is the core feature of Renfe Tracker. Once you find a train you\'re interested in, you can track it \u2014 the app will periodically check the price and record every change, so you always know when to buy.","sidebar":"docsSidebar"},"installation":{"id":"installation","title":"Installation","description":"Renfe Tracker is distributed as a Docker image. The recommended way to run it is with Docker Compose, but plain docker run and local development without Docker are also supported.","sidebar":"docsSidebar"},"intro":{"id":"intro","title":"Introduction","description":"Renfe Tracker is a self-hosted web application that monitors Spanish Renfe train prices (Media/Larga Distancia) and alerts you when they change. It runs entirely inside a single Docker container \u2014 no cloud accounts, no subscriptions, no third-party services required.","sidebar":"docsSidebar"}}}}')}}]);